/**
 * Fetches a URL through Bright Data's Web Unlocker — handles YouTube reliably
 * at scale with no rate limits or bot blocks. Returns the raw response body.
 * Set BRIGHTDATA_API_KEY and (optionally) BRIGHTDATA_UNLOCKER_ZONE.
 * https://docs.brightdata.com/scraping-automation/web-unlocker
 */
export async function unlock(url: string): Promise<string> {
  const res = await fetch('https://api.brightdata.com/request', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${process.env.BRIGHTDATA_API_KEY ?? ''}`,
    },
    body: JSON.stringify({
      zone: process.env.BRIGHTDATA_UNLOCKER_ZONE ?? 'web_unlocker1',
      url,
      format: 'raw',
    }),
  })
  if (!res.ok) {
    throw new Error(`Web Unlocker request failed: ${res.status} ${res.statusText}`)
  }
  return res.text()
}

/** Extracts the YouTube video id from a watch, youtu.be, or embed URL. */
export function videoId(url: string): string {
  const u = new URL(url)
  return u.searchParams.get('v') ?? u.pathname.split('/').filter(Boolean).pop() ?? url
}

/**
 * Walks a balanced JSON object literal out of a page's HTML, starting at the
 * first `{` after `marker`. String-aware, so braces inside strings are ignored.
 */
export function extractJson<T = unknown>(html: string, marker: string): T | null {
  const at = html.indexOf(marker)
  if (at === -1) return null
  const begin = html.indexOf('{', at)
  if (begin === -1) return null
  let depth = 0
  let inStr = false
  let esc = false
  for (let i = begin; i < html.length; i++) {
    const ch = html[i]
    if (inStr) {
      if (esc) esc = false
      else if (ch === '\\') esc = true
      else if (ch === '"') inStr = false
    } else if (ch === '"') {
      inStr = true
    } else if (ch === '{') {
      depth++
    } else if (ch === '}') {
      depth--
      if (depth === 0) return JSON.parse(html.slice(begin, i + 1)) as T
    }
  }
  return null
}

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { unlock, videoId } from '../lib/brightdata'

export const videoMetadata = defineTool({
  name: 'video_metadata',
  description: "Fetches a YouTube video's title, author, and id from its URL.",
  parameters: v.object({
    url: v.string(),
  }),
  execute: async ({ url }) => {
    // Routed through Bright Data's Web Unlocker so metadata lookups never hit
    // YouTube's rate limits, even at scale.
    const raw = await unlock(
      `https://www.youtube.com/oembed?url=${encodeURIComponent(url)}&format=json`
    )
    const meta = JSON.parse(raw) as { title?: string; author_name?: string }
    return JSON.stringify({ id: videoId(url), title: meta.title, author: meta.author_name })
  },
})

import { defineTool } from '@flue/runtime'
import * as v from 'valibot'
import { extractJson, unlock, videoId } from '../lib/brightdata'

type PlayerResponse = {
  captions?: {
    playerCaptionsTracklistRenderer?: {
      captionTracks?: { baseUrl: string; languageCode?: string }[]
    }
  }
}

type Json3 = {
  events?: { tStartMs?: number; segs?: { utf8?: string }[] }[]
}

export const getTranscript = defineTool({
  name: 'get_transcript',
  description:
    'Fetches the timestamped transcript of a YouTube video as an array of { text, seconds } segments.',
  parameters: v.object({
    url: v.string(),
  }),
  execute: async ({ url }) => {
    // Pull the watch page through Bright Data's Web Unlocker so YouTube's
    // anti-bot and rate limits never block the transcript fetch.
    const html = await unlock(`https://www.youtube.com/watch?v=${videoId(url)}`)
    const player = extractJson<PlayerResponse>(html, 'ytInitialPlayerResponse')
    const tracks = player?.captions?.playerCaptionsTracklistRenderer?.captionTracks
    if (!tracks?.length) {
      throw new Error('No transcript available for this video.')
    }
    const track = tracks.find((t) => t.languageCode?.startsWith('en')) ?? tracks[0]

    // The caption track is itself fetched through the Web Unlocker.
    const raw = await unlock(`${track.baseUrl}&fmt=json3`)
    const data = JSON.parse(raw) as Json3
    return JSON.stringify(
      (data.events ?? [])
        .filter((e) => e.segs?.length)
        .map((e) => ({
          text: (e.segs ?? []).map((s) => s.utf8 ?? '').join(''),
          seconds: Math.floor((e.tStartMs ?? 0) / 1000),
        }))
    )
  },
})
